class Solution:
    def superEggDrop(self, k: int, n: int) -> int:
        memo = dict()
        def dp(k, n):
            if (k, n) in memo:
                return memo[(k, n)]
            if n == 0:
                return 0
            if k == 1:
                return n
            res = float('inf')
            for x in range(1, n + 1):
                res = min(res, 1 + max(dp(k - 1, x - 1), dp(k, n - x)))
            memo[(k, n)] = res
            return res
        return dp(k, n)
